package queries

import (
	"context"
	"fmt"
)

// CreateProduct creates a new product
// Generated by SQLC from products.sql
func (q *Queries) CreateProduct(ctx context.Context, sku string, name string, description *string, price string) (Product, error) {
	row := q.db.QueryRow(ctx,
		`INSERT INTO products (sku, name, description, price)
		 VALUES ($1, $2, $3, $4)
		 RETURNING id, sku, name, description, price, created_at, updated_at`,
		sku, name, description, price)

	var i Product
	err := row.Scan(
		&i.ID,
		&i.Sku,
		&i.Name,
		&i.Description,
		&i.Price,
		&i.CreatedAt,
		&i.UpdatedAt,
	)
	return i, err
}

